document.addEventListener("submit",async e=>{const f=e.target;if(!f.matches("[hx-post]"))return;e.preventDefault();const r=await fetch(f.getAttribute("hx-post"),{method:"POST",body:new FormData(f)});if(r.redirected){location.href=r.url;return}const t=f.getAttribute("hx-target");if(t){document.querySelector(t).innerHTML=await r.text()}});
